import java.io.*;  // Import of InputStreams & OutputStreams classes from Java Standard Library (Stdlib)  
import java.net.*; // Package for handling networking tasks in general and specific to socket programming e.g., SocketAddress, ServerSocket etc.   

public class java_52259_SocketServer_A01 {  // Define the server program as a public static method within an outermost "class" which is named 'VanillaJava' (standard Java naming convention).  
    
// Main Method: The main entry point to any application- Program execution starts here.    Starts up by creating socket and binding it with port 1234 for listening on incoming connections from clients, then waits until a client is connected using accept(). This method returns the accepted sockethandle which can be used as input/output stream of communication within that specific thread to communicate over this connection.   
     public static void main(String args[]) {   //Main Method Declaration in Java standard language and requires parameters (string array).  Main is your entry point from where the program starts running once it's loaded by JVM ie., "main" method at start of execution, same as a java application.
         ServerSocket server = null;      //Define variable to store socket address for listening into connections and accepting them   using 'ServerSocker'.  This is standard Java library not specific or creative in nature but required by the code below (socket programming).    Data structures of Standard Library, like List & Set are essential when you work with sockets.
         try {     //try statement to enclose all possible errors that can occur during execution e.g., OutOfMemoryError if there is insufficient memory available or IOException for network related issues   (socket programming). 
            server = new ServerSocket(1234);    //create a 'ServerSocker' and bind it with port number of your choice, accepting connections on this socket from clients.     This operation will block until something connects to the client using accept() method in while loop below if multiple sockets are connected simultaneously (multithreading).
            System.out.println("Waiting for a connection... ");   //Prompt user by printing message about waiting for incoming connections, same as starting of socket server program on console/terminal window where you can see your 'status'.    This is required to let the client know it's connected and ready to communicate with this particular application.
            
            Socket sock = null;     //Define a variable (Socket) for holding address information once accepted from clients, same as when accepting connection by calling accept().   It can be used later in sending/receiving data over established socket communication channel e..g., using InputStream and OutputStream.
            
            while(true){    //create loop to keep server running until explicitly stopped or exception is thrown (Break statement will stop the whole process).  This needs a condition because our program should continue listening for connections even after it has been manually shut down by user, otherwise we'll be in an infinite waiting state.
                try {     //try block around socket related operations e..g., bind or listen might fail if already bound to certain port number and unable due some other reason ie server is not running properly as expected/due the application error etc (socket programming).    This blocks until complete operation can be executed successfully, hence providing a reliable way of handling exceptions in our code.
                    sock = server.accept();     //blocks here untill it receives connection request from client on established socket e..g., if there's no other user trying to connect this port and is free for use by the new connecting users/clients, will accept() method can return a valid Socket object which we store in 'socket'.
                    System.out.println("Connection accepted!");   //Prompt message after successfully accepting connection from client on console window (for user feedback).  It's required to notify that the server has connected with this specific application instance and it is ready for sending/receiving data over established socket communication channel e..g., using InputStream & OutputStream.
                    
                    DataOutputStream out = new DataOutputStream( sock.getOutputStream());     //Get output stream from 'socket' (used to send back response or acknowledging the received client request).  Same as when sending message on server side over socket communication channel e..g., using Inputstream & OutputStreams like PrintWriter, BufferedReader etc for this purpose
                     DataInputStream in = new DataInputStream( sock.getInputStream());     //Get input stream from 'socket' (used to receive data or requests sent by client). Same as when reading message on server side over socket communication channel e..g., using InputStream & OutputStreams like BufferedReader, PrintWriter etc for this purpose
                     String received = in .readUTF();    //Read a text line from the connected user.  This is used to receive and print back any data sent by client that arrives on established connection socket communication channel e..g., using Inputstream & OutputStreams like BufferedReader, PrintWriter etc for this purpose
                     System.out.println("Received: " + received);   //Prompt message after receiving text line from the connected user in console window (for feedback). Same as when you receive a response or acknowledging client request on server side over socket communication channel e..g., using InputStream & OutputStreams like DataOutputStream, PrintWriter etc for this purpose
                     out .writeUTF("Hello Client");   //Send back "Hello Client" to connected user.  This is used with sending any data message from the application instance that can be received and processed by client on established connection socket communication channel e..g., using InputStream & OutputStreams like DataOutputStream, PrintWriter etc for this purpose
                     sock.close();    //Close 'socket' once done to free up resources (this is a requirement when all threads are complete).  Same as closing the outputstream and input stream after use by corresponding thread or server instance e..g., using close() method in InputOutputStream classes only, otherwise you might get unexpected behavior due socket communication.
                } catch(IOException i) {   //Catch block to handle I/O exceptions that may occur during execution (socket programming).  In Java as with all standard libraries and language constructs this is a requirement of handling any type or number issues related specifically on error, exception etc in the program like network down issue if socket fails for some reason.
                    i.printStackTrace(); //Print Exception's stack trace to console (This allows you debugging process by printing out exceptions details).  In Java this is necessary as a general rule no matter how many lines of code your application has, it will print the error message and stop executing on that line if an exception occurs in run time.
                    server = null; //If there's any I/O Exception or some other type os exceptions occur then we need to close down all resources as soon possible (closing socket connection etc).  Otherwise you might face memory leaks, thread execution gets interrupted and so on further issues when application is running due exception.
                }   
            //End of While loop after it's done with 'server'.   It must be manually stopped or programmed to stop once user wants us to terminate e..g., via system command line/terminal window etc (when all threads are completed).  This prevents resource leaks and keeps server running smoothly.
             } //End of main method after try-catch block execution as it will get handled when exception occurs by catch statement above in while loop or once 'server' is manually closed due to some user operation like command line stop etc (closing socket connection, if necessary).  This ensures resource cleanup and server ends gracefully.
          } finally {    //finally block after try-catch as it will execute no matter what happens inside the code in surrounding blocks e..g., closing Database connections or file handles which have been opened by previous codes but never closed due to some exception occur, etc (this is important if you want your server shutdown procedure be able run even when exceptions occurs).  This ensures all resource deallocation and cleanup work are done.
            //This block of code will execute no matter what happened inside the try-catch blocks above e..g., after catching IOExceptions, closing socket etc (this is important for proper server shutdown procedure in case any abruptly stops occur).  This ensures all resource deallocation and cleanup work are done.
            if(server != null) {   //This block will only execute when 'main' method ends due to some unexpected reason other than normal termination or system command stop etc (closing socket connection, file handles e..g., after handling Inputstream & OutputStreams correctly).  It ensures that server is shut down properly by closing all open connections and free resources.
                try {     //Catch block for if there're any exception while trying to close the ServerSocket which might occur due network issues or in case of an issue on shutdown command line etc (closing socket connection, file handles e..g., after handling Inputstream & OutputStreams correctly).  This will ensure server is shut down properly by closing all open connections and free resources.
                    server.close(); //Close ServerSocket which should finally close the listening port for other clients to connect back on it (if necessary) once shutdown command line or abruptly stopped occurs like when network issues, etc happen later in your program execution due socket programming related operations e..g., closing a client’s input & output streams.
                } catch(IOException i){  //Catch block for handling I/O exceptions that occur while trying to close ServerSocket if any problem with graceful shutdown command line stop occurs like when network issues, etc happen later in your program execution due socket programming related operations e..g., closing a client’s input & output streams.
                    i.printStackTrace();  //Print exception's stack trace for debugging purposes to console (this allows you Debug the process by printing out exceptions details). In Java this is necessary as often when all threads are complete, it will print error message and stops executing on that line if any runtime errors occur in run time e..g., closing a client’s input & output streams.
                }    //End of catch block for handling I/O Exception during try-catch Block execution due to socket programming related operations like close() method, which will ensure server is shutdown properly by gracefully stopping all open connections and freeing up resources when shut down command line or abruptly stopped occurs (closes client's input & output streams).
             }  //End of if statement block after main-try catch execution as it handles the exit from 'main'.   Once this happens because user have manually requested to quit application. It ensures all resource deallocation and cleanup work are done which prevents any memory leaks or other unexpected behavior caused by abrupt termination on command line stop, etc (closing socket connection).
        }  //End of main method execution as it wraps around the try-catch block above for handling exceptions during programmatic operations like server shutdown procedure.   This ensures all resource deallocation and cleanup work is done when shut down due to user operation such command line stop or abrupt termination occurs etc (closing socket connection).
    }  //End of main method execution as it wraps around the try-catch block above for handling exceptions during programmatic operations like server shutdown procedure.   This ensures all resource deallocation and cleanup work is done when shut down due to user operation such command line stop or abrupt termination occurs etc (closing socket connection).
}  //End of main method execution as it wraps around the try-catch block above for handling exceptions during programmatic operations like server shutdown procedure.   This ensures all resource deallocation and cleanup work is done when shut down due to user operation such command line stop or abrupt termination occurs etc (closing socket connection).